import{_ as a,o as e,c as l,a2 as r}from"./chunks/framework.BQ1gajhD.js";const u=JSON.parse('{"title":"奥林匹克森林公园","description":"","frontmatter":{},"headers":[],"relativePath":"parks/olympic-forest.md","filePath":"parks/olympic-forest.md","lastUpdated":null}'),o={name:"parks/olympic-forest.md"};function i(n,t,d,s,h,g){return e(),l("div",null,[...t[0]||(t[0]=[r('<h1 id="奥林匹克森林公园" tabindex="-1">奥林匹克森林公园 <a class="header-anchor" href="#奥林匹克森林公园" aria-label="Permalink to &quot;奥林匹克森林公园&quot;">​</a></h1><blockquote><p>&quot;北京最大的城市公园，城市中的绿肺。&quot;</p></blockquote><h2 id="简介" tabindex="-1">简介 <a class="header-anchor" href="#简介" aria-label="Permalink to &quot;简介&quot;">​</a></h2><p>奥林匹克森林公园位于北京市朝阳区，是北京奥林匹克公园的重要组成部分，也是北京最大的城市公园。公园占地约680公顷，是北京&quot;绿肺&quot;，也是市民休闲健身的好去处。</p><h2 id="基本信息" tabindex="-1">基本信息 <a class="header-anchor" href="#基本信息" aria-label="Permalink to &quot;基本信息&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">项目</th><th style="text-align:left;">内容</th></tr></thead><tbody><tr><td style="text-align:left;"><strong>开放时间</strong></td><td style="text-align:left;">全天开放</td></tr><tr><td style="text-align:left;"><strong>门票价格</strong></td><td style="text-align:left;">免费</td></tr><tr><td style="text-align:left;"><strong>建议游玩</strong></td><td style="text-align:left;">半天至一天</td></tr><tr><td style="text-align:left;"><strong>最佳季节</strong></td><td style="text-align:left;">春秋两季</td></tr><tr><td style="text-align:left;"><strong>交通方式</strong></td><td style="text-align:left;">地铁8号线森林公园南门站</td></tr><tr><td style="text-align:left;"><strong>地址</strong></td><td style="text-align:left;">北京市朝阳区科荟路33号</td></tr></tbody></table><h2 id="历史沿革" tabindex="-1">历史沿革 <a class="header-anchor" href="#历史沿革" aria-label="Permalink to &quot;历史沿革&quot;">​</a></h2><h3 id="规划建设" tabindex="-1">规划建设 <a class="header-anchor" href="#规划建设" aria-label="Permalink to &quot;规划建设&quot;">​</a></h3><p>奥林匹克森林公园是北京奥运会的重要配套设施，2003年开始规划建设，2008年北京奥运会前建成开放。</p><h3 id="设计" tabindex="-1">设计 <a class="header-anchor" href="#设计" aria-label="Permalink to &quot;设计&quot;">​</a></h3><p>公园由中外著名景观设计师设计，以&quot;通往自然的轴线&quot;为设计理念，体现了中国传统文化与现代生态理念的融合。</p><h3 id="生态功能" tabindex="-1">生态功能 <a class="header-anchor" href="#生态功能" aria-label="Permalink to &quot;生态功能&quot;">​</a></h3><p>奥林匹克森林公园是北京重要的生态屏障，承担着调节气候、净化空气、涵养水源等生态功能。</p><h2 id="园区布局" tabindex="-1">园区布局 <a class="header-anchor" href="#园区布局" aria-label="Permalink to &quot;园区布局&quot;">​</a></h2><p>奥林匹克森林公园分为南园和北园两部分。</p><h3 id="南园" tabindex="-1">南园 <a class="header-anchor" href="#南园" aria-label="Permalink to &quot;南园&quot;">​</a></h3><p>南园以大型山水景观为主，有奥海、仰山等景点。</p><h4 id="奥海" tabindex="-1">奥海 <a class="header-anchor" href="#奥海" aria-label="Permalink to &quot;奥海&quot;">​</a></h4><p>奥海是公园内最大的人工湖，面积约28公顷。湖边有亲水平台、木栈道等休闲设施。</p><h4 id="仰山" tabindex="-1">仰山 <a class="header-anchor" href="#仰山" aria-label="Permalink to &quot;仰山&quot;">​</a></h4><p>仰山是公园内的制高点，海拔约86米。登上仰山，可以俯瞰整个奥林匹克公园。</p><h4 id="奥林匹克宣言广场" tabindex="-1">奥林匹克宣言广场 <a class="header-anchor" href="#奥林匹克宣言广场" aria-label="Permalink to &quot;奥林匹克宣言广场&quot;">​</a></h4><p>广场上有奥林匹克宣言纪念碑，刻有《奥林匹克宣言》全文。</p><h3 id="北园" tabindex="-1">北园 <a class="header-anchor" href="#北园" aria-label="Permalink to &quot;北园&quot;">​</a></h3><p>北园以自然野趣为主，有大片的森林、湿地。</p><h4 id="生态廊道" tabindex="-1">生态廊道 <a class="header-anchor" href="#生态廊道" aria-label="Permalink to &quot;生态廊道&quot;">​</a></h4><p>北园有生态廊道，连接南园和北园，是野生动物的通道。</p><h4 id="湿地" tabindex="-1">湿地 <a class="header-anchor" href="#湿地" aria-label="Permalink to &quot;湿地&quot;">​</a></h4><p>北园有大片湿地，是鸟类栖息的好地方。</p><h2 id="生态特色" tabindex="-1">生态特色 <a class="header-anchor" href="#生态特色" aria-label="Permalink to &quot;生态特色&quot;">​</a></h2><h3 id="植物种类" tabindex="-1">植物种类 <a class="header-anchor" href="#植物种类" aria-label="Permalink to &quot;植物种类&quot;">​</a></h3><p>奥林匹克森林公园种植了100余种植物，包括：</p><ul><li><strong>乔木</strong>：银杏、国槐、白蜡、油松等</li><li><strong>灌木</strong>：丁香、连翘、月季等</li><li><strong>花卉</strong>：牡丹、芍药、荷花等</li><li><strong>水生植物</strong>：芦苇、菖蒲、荷花等</li></ul><h3 id="动物种类" tabindex="-1">动物种类 <a class="header-anchor" href="#动物种类" aria-label="Permalink to &quot;动物种类&quot;">​</a></h3><p>公园内有丰富的野生动物资源：</p><ul><li><strong>鸟类</strong>：野鸭、白鹭、喜鹊等</li><li><strong>鱼类</strong>：鲫鱼、鲤鱼等</li><li><strong>昆虫</strong>：蝴蝶、蜻蜓等</li></ul><h3 id="生态监测站" tabindex="-1">生态监测站 <a class="header-anchor" href="#生态监测站" aria-label="Permalink to &quot;生态监测站&quot;">​</a></h3><p>公园内有生态监测站，实时监测空气质量、水质等生态指标。</p><h2 id="游览项目" tabindex="-1">游览项目 <a class="header-anchor" href="#游览项目" aria-label="Permalink to &quot;游览项目&quot;">​</a></h2><h3 id="健步道" tabindex="-1">健步道 <a class="header-anchor" href="#健步道" aria-label="Permalink to &quot;健步道&quot;">​</a></h3><p>公园内有10公里长的塑胶健步道，是跑步爱好者的天堂。</p><h3 id="自行车道" tabindex="-1">自行车道 <a class="header-anchor" href="#自行车道" aria-label="Permalink to &quot;自行车道&quot;">​</a></h3><p>公园内有自行车专用道，可以骑自行车游览。</p><h3 id="游船" tabindex="-1">游船 <a class="header-anchor" href="#游船" aria-label="Permalink to &quot;游船&quot;">​</a></h3><p>夏季可以在奥海划船，欣赏湖光山色。</p><h3 id="观鸟" tabindex="-1">观鸟 <a class="header-anchor" href="#观鸟" aria-label="Permalink to &quot;观鸟&quot;">​</a></h3><p>北园湿地是观鸟的好地方，春秋两季鸟类较多。</p><h2 id="游览攻略" tabindex="-1">游览攻略 <a class="header-anchor" href="#游览攻略" aria-label="Permalink to &quot;游览攻略&quot;">​</a></h2><h3 id="推荐路线" tabindex="-1">推荐路线 <a class="header-anchor" href="#推荐路线" aria-label="Permalink to &quot;推荐路线&quot;">​</a></h3><p><strong>经典路线（约3-4小时）</strong>：</p><p>南门 → 奥海 → 仰山 → 奥林匹克宣言广场 → 生态廊道 → 北园湿地 → 北门</p><p><strong>跑步路线（10公里）</strong>：</p><p>沿着健步道跑一圈，约10公里。</p><p><strong>骑行路线</strong>：</p><p>沿着自行车道骑行，可以绕公园一周。</p><h3 id="交通方式" tabindex="-1">交通方式 <a class="header-anchor" href="#交通方式" aria-label="Permalink to &quot;交通方式&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">方式</th><th style="text-align:left;">站点</th></tr></thead><tbody><tr><td style="text-align:left;">地铁</td><td style="text-align:left;">8号线森林公园南门站或林萃桥站</td></tr><tr><td style="text-align:left;">公交</td><td style="text-align:left;">510路、81路、快速公交3线等</td></tr><tr><td style="text-align:left;">自驾</td><td style="text-align:left;">公园有停车场</td></tr></tbody></table><h3 id="实用贴士" tabindex="-1">实用贴士 <a class="header-anchor" href="#实用贴士" aria-label="Permalink to &quot;实用贴士&quot;">​</a></h3><ol><li><strong>全天开放</strong>：24小时开放，随时可以进入</li><li><strong>免费入园</strong>：免费入园</li><li><strong>健身天堂</strong>：跑步、骑行、健身的好地方</li><li><strong>春秋最美</strong>：春秋两季景色最美</li><li><strong>避开高峰</strong>：周末人较多，建议工作日</li><li><strong>自备饮水</strong>：园内卖水点较少</li><li><strong>注意防晒</strong>：夏季注意防晒</li></ol><h2 id="周边景点" tabindex="-1">周边景点 <a class="header-anchor" href="#周边景点" aria-label="Permalink to &quot;周边景点&quot;">​</a></h2><table tabindex="0"><thead><tr><th style="text-align:left;">景点</th><th style="text-align:center;">距离</th><th style="text-align:left;">特色</th></tr></thead><tbody><tr><td style="text-align:left;">鸟巢（国家体育场）</td><td style="text-align:center;">紧邻</td><td style="text-align:left;">2008奥运主会场</td></tr><tr><td style="text-align:left;">水立方（国家游泳中心）</td><td style="text-align:center;">紧邻</td><td style="text-align:left;">奥运游泳场馆</td></tr><tr><td style="text-align:left;">中国科技馆</td><td style="text-align:center;">紧邻</td><td style="text-align:left;">国家级科技馆</td></tr><tr><td style="text-align:left;">奥林匹克塔</td><td style="text-align:center;">紧邻</td><td style="text-align:left;">俯瞰奥运公园</td></tr><tr><td style="text-align:left;">中国工艺美术馆</td><td style="text-align:center;">步行15分钟</td><td style="text-align:left;">传统工艺</td></tr></tbody></table><h2 id="生态价值" tabindex="-1">生态价值 <a class="header-anchor" href="#生态价值" aria-label="Permalink to &quot;生态价值&quot;">​</a></h2><p>奥林匹克森林公园是北京最重要的生态绿地，每年可吸收二氧化碳约12万吨，释放氧气约8万吨，被称为北京的&quot;绿肺&quot;。</p><p>公园还承担着涵养水源、调节气候、净化空气等生态功能，是北京城市生态系统的重要组成部分。</p><hr><p><strong>📍 地址</strong>：北京市朝阳区科荟路33号 <strong>📞 电话</strong>：010-64529088</p>',66)])])}const b=a(o,[["render",i]]);export{u as __pageData,b as default};
